sql:
SELECT criterion_id, AVG(weight) AS average_weight
FROM evaluation_criteria
GROUP BY criterion_id;

SELECT title, year
FROM research_contributions
WHERE status = 'Published';

SELECT type, COUNT(*) AS contribution_count
FROM research_contributions
GROUP BY type;

SELECT COUNT(contribution_id) AS total_contributions
FROM research_contributions
WHERE year = 2022;

SELECT title, year
FROM research_contributions
WHERE contribution_id = 0;

